+// GENERATED BY NAPL from text_diff.md — edit the prompt, not this file
+//! Line-oriented text diffing.
+//!
+//! Produces and parses a unified diff between two texts, line by line, using a
+//! longest-common-subsequence alignment. Pure: no I/O, no dependencies on other
+//! project modules.
+
+/// The kind of a hunk line.
+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+pub enum HunkKind {
+    Context,
+    Del,
+    Ins,
+}
+
+/// A single line within a hunk.
+#[derive(Debug, Clone, PartialEq, Eq)]
+pub struct HunkLine {
+    pub kind: HunkKind,
+    pub text: String,
+}
+
+/// A parsed unified-diff hunk.
+#[derive(Debug, Clone, PartialEq, Eq)]
+pub struct Hunk {
+    pub old_start: usize,
+    pub old_count: usize,
+    pub new_start: usize,
+    pub new_count: usize,
+    pub lines: Vec<HunkLine>,
+}
+
+/// Split `text` into its lines as owned strings.
+///
+/// Empty text has no lines. Otherwise a single trailing terminator (`\n` or
+/// `\r\n`) is removed, then the text is split on each `\n`; a `\r` immediately
+/// before a split `\n` is consumed with it, but a lone `\r` stays in the line.
+pub fn to_lines(text: &str) -> Vec<String> {
+    if text.is_empty() {
+        return Vec::new();
+    }
+
+    // Strip a single trailing terminator.
+    let body = if let Some(stripped) = text.strip_suffix("\r\n") {
+        stripped
+    } else if let Some(stripped) = text.strip_suffix('\n') {
+        stripped
+    } else {
+        text
+    };
+
+    body.split('\n')
+        .map(|line| line.strip_suffix('\r').unwrap_or(line).to_string())
+        .collect()
+}
+
+/// An aligned entry between `before` and `after`.
+enum Entry {
+    Context { old: usize, new: usize, text: String },
+    Del { old: usize, text: String },
+    Ins { new: usize, text: String },
+}
+
+/// Align `before` and `after` lines via longest-common-subsequence.
+fn align(before: &[String], after: &[String]) -> Vec<Entry> {
+    let n = before.len();
+    let m = after.len();
+
+    // LCS length table.
+    let mut lcs = vec![vec![0usize; m + 1]; n + 1];
+    for i in (0..n).rev() {
+        for j in (0..m).rev() {
+            lcs[i][j] = if before[i] == after[j] {
+                lcs[i + 1][j + 1] + 1
+            } else {
+                lcs[i + 1][j].max(lcs[i][j + 1])
+            };
+        }
+    }
+
+    let mut entries = Vec::new();
+    let mut i = 0;
+    let mut j = 0;
+    while i < n && j < m {
+        if before[i] == after[j] {
+            entries.push(Entry::Context {
+                old: i + 1,
+                new: j + 1,
+                text: before[i].clone(),
+            });
+            i += 1;
+            j += 1;
+        } else if lcs[i + 1][j] >= lcs[i][j + 1] {
+            entries.push(Entry::Del {
+                old: i + 1,
+                text: before[i].clone(),
+            });
+            i += 1;
+        } else {
+            entries.push(Entry::Ins {
+                new: j + 1,
+                text: after[j].clone(),
+            });
+            j += 1;
+        }
+    }
+    while i < n {
+        entries.push(Entry::Del {
+            old: i + 1,
+            text: before[i].clone(),
+        });
+        i += 1;
+    }
+    while j < m {
+        entries.push(Entry::Ins {
+            new: j + 1,
+            text: after[j].clone(),
+        });
+        j += 1;
+    }
+    entries
+}
+
+/// Produce a unified diff with 3 lines of surrounding context.
+pub fn unified_diff(before: &str, after: &str) -> String {
