+    let normalized = rel_full.replace('\\', "/");
+    let rest = normalized.strip_prefix(GENERATED_PREFIX)?;
+    let slash_idx = rest.find('/')?;
+    let target = &rest[..slash_idx];
+    let target_rel_path = &rest[slash_idx + 1..];
+    if target.is_empty() || target_rel_path.is_empty() {
