+pub fn code_lens_title(prompt_basename: &str, absolute_line: usize, note: &str) -> String {
+    if note.is_empty() {
+        format!("⇠ {prompt_basename}:{absolute_line}")
+    } else {
+        format!("⇠ {prompt_basename}:{absolute_line} — {note}")
+    }
