+pub fn dedupe_matches(matches: &[ReverseMatch]) -> Vec<ReverseMatch> {
+    let mut seen = std::collections::HashSet::new();
+    let mut result = Vec::new();
+    for m in matches {
+        let key = (m.prompt_file.clone(), m.prompt_lines.start, m.prompt_lines.end);
+        if seen.insert(key) {
