+// GENERATED BY NAPL from schemas_journal.napl — edit the prompt, not this file
+//! The generation journal: an append-only JSONL history.
+//!
+//! Serde types and pure readers for the NAPL generation journal — one entry
+//! per generation of a module against a target. No I/O: the caller reads the
+//! file, this module parses the text.
+
+use blame::BlameSourceEntry;
+use serde::{Deserialize, Serialize};
+
+/// One file touched by a generation.
+#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
+pub struct JournalFile {
+    pub path: String,
+    pub patch: String,
+    #[serde(rename = "hashBefore")]
+    pub hash_before: Option<String>,
+    #[serde(rename = "hashAfter")]
+    pub hash_after: String,
+}
+
+/// The mode a generation ran in.
+#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
+#[serde(rename_all = "lowercase")]
+pub enum JournalMode {
+    Full,
+    Incremental,
+    Reconcile,
+}
+
+/// One generation of a module against a target.
+#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
+pub struct JournalEntry {
+    pub gen: i64,
+    pub timestamp: String,
+    pub module: String,
+    pub target: String,
+    #[serde(rename = "promptHash")]
+    pub prompt_hash: String,
+    #[serde(rename = "promptDiff")]
+    pub prompt_diff: String,
+    pub mode: JournalMode,
+    #[serde(default)]
+    pub files: Vec<JournalFile>,
+}
+
+/// The unified diff for a created (`before: None`) or modified file.
+pub fn file_patch(before: Option<&str>, after: &str) -> String {
+    text_diff::unified_diff(before.unwrap_or(""), after)
+}
+
+fn entry_is_valid(entry: &JournalEntry) -> bool {
+    entry.gen >= 1
+        && !entry.module.is_empty()
+        && !entry.target.is_empty()
+        && entry.files.iter().all(|f| !f.path.is_empty())
+}
+
+/// Parse raw JSONL journal text, returning valid entries and one warning per
+/// skipped line.
+pub fn read_journal_str(raw: &str) -> (Vec<JournalEntry>, Vec<String>) {
+    let mut entries = Vec::new();
+    let mut warnings = Vec::new();
+
+    for (idx, raw_line) in raw.split('\n').enumerate() {
+        let line_number = idx + 1;
+        let line = raw_line.strip_suffix('\r').unwrap_or(raw_line);
+
+        if line.trim().is_empty() {
+            continue;
+        }
+
+        match serde_json::from_str::<JournalEntry>(line) {
+            Ok(entry) if entry_is_valid(&entry) => entries.push(entry),
+            Ok(_) => warnings.push(format!(
+                "line {line_number}: journal entry failed validation"
+            )),
+            Err(err) => warnings.push(format!("line {line_number}: {err}")),
+        }
+    }
+
+    (entries, warnings)
+}
+
+/// One past the highest `gen` among `entries`, or `1` for an empty slice.
+pub fn next_gen_number(entries: &[JournalEntry]) -> i64 {
+    entries.iter().map(|e| e.gen).max().map_or(1, |g| g + 1)
+}
+
+/// The blame-source history of `file_path` across `entries`, in entry order.
+pub fn file_history(entries: &[JournalEntry], file_path: &str) -> Vec<BlameSourceEntry> {
+    entries
+        .iter()
+        .filter_map(|entry| {
+            entry
+                .files
+                .iter()
+                .find(|f| f.path == file_path)
+                .map(|f| BlameSourceEntry {
+                    gen: entry.gen,
+                    timestamp: entry.timestamp.clone(),
+                    module: entry.module.clone(),
+                    patch: f.patch.clone(),
+                    prompt_diff: entry.prompt_diff.clone(),
+                })
+        })
+        .collect()
+}
