+/// Returns the last `count` characters (Unicode scalar values) of `text`; if
+/// `text` has `count` or fewer characters, returns the whole `text`.
+pub fn last_chars(text: &str, count: usize) -> String {
+    let total = text.chars().count();
+    if total <= count {
+        return text.to_string();
+    }
+    text.chars().skip(total - count).collect()
+}
